import{_ as a,o as s,c as n,a2 as i}from"./chunks/framework.N9BN-Nr4.js";const u=JSON.parse('{"title":"Horde Magic: A New Way To Play Magic And Survive Zombie Invasions","description":"","frontmatter":{},"headers":[],"relativePath":"formats/horde/sources/original-horde-magic-quiet-speculation.md","filePath":"formats/horde/sources/original-horde-magic-quiet-speculation.md","lastUpdated":1782025909000}'),t={name:"formats/horde/sources/original-horde-magic-quiet-speculation.md"};function r(l,e,o,d,c,p){return s(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="horde-magic-a-new-way-to-play-magic-and-survive-zombie-invasions" tabindex="-1">Horde Magic: A New Way To Play Magic And Survive Zombie Invasions <a class="header-anchor" href="#horde-magic-a-new-way-to-play-magic-and-survive-zombie-invasions" aria-label="Permalink to &quot;Horde Magic: A New Way To Play Magic And Survive Zombie Invasions&quot;">​</a></h1><p>Source: <a href="https://www.quietspeculation.com/2011/09/horde-magic-a-new-way-to-play-magic-and-survive-zombie-invasions/" target="_blank" rel="noreferrer">https://www.quietspeculation.com/2011/09/horde-magic-a-new-way-to-play-magic-and-survive-zombie-invasions/</a></p><p>Author: Peter Knudson<br> Published: September 29, 2011</p><p>This is the original Horde Magic article. It introduces the format as a cooperative Magic variant where players team up against an automated Zombie Horde deck.</p><h2 id="premise" tabindex="-1">Premise <a class="header-anchor" href="#premise" aria-label="Permalink to &quot;Premise&quot;">​</a></h2><p>Horde Magic is framed as &quot;Left 4 Dead&quot; Magic: the players are Survivors trying to outlast a zombie apocalypse.</p><p>The Horde has no pilot, no hand, and no life total. It attacks relentlessly. The players win by surviving long enough to exhaust the Horde deck and clear the battlefield.</p><h2 id="basic-setup" tabindex="-1">Basic Setup <a class="header-anchor" href="#basic-setup" aria-label="Permalink to &quot;Basic Setup&quot;">​</a></h2><ul><li>Each Survivor uses a Commander deck, though the article notes that other Magic decks can work.</li><li>One to four Survivors play cooperatively.</li><li>Survivors share a life total.</li><li>The Horde deck starts with no hand and no permanents.</li><li>Survivors take three setup turns before the Horde takes its first turn.</li><li>After setup, the Survivors and Horde alternate turns.</li></ul><h2 id="horde-deck-size-by-player-count" tabindex="-1">Horde Deck Size By Player Count <a class="header-anchor" href="#horde-deck-size-by-player-count" aria-label="Permalink to &quot;Horde Deck Size By Player Count&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Survivors</th><th style="text-align:right;">Horde Deck Size</th></tr></thead><tbody><tr><td style="text-align:right;">1</td><td style="text-align:right;">45 cards</td></tr><tr><td style="text-align:right;">2</td><td style="text-align:right;">60 cards</td></tr><tr><td style="text-align:right;">3</td><td style="text-align:right;">75 cards</td></tr><tr><td style="text-align:right;">4</td><td style="text-align:right;">100 cards</td></tr></tbody></table><p>The article&#39;s method is to build a 100-card Horde deck, then randomly remove cards for smaller player counts.</p><h2 id="survivor-rules" tabindex="-1">Survivor Rules <a class="header-anchor" href="#survivor-rules" aria-label="Permalink to &quot;Survivor Rules&quot;">​</a></h2><ul><li>Survivors act like a team.</li><li>Survivors take their turns simultaneously.</li><li>Survivors attack and block as a team.</li><li>The shared life total is 20 life per player.</li></ul><h2 id="horde-turn" tabindex="-1">Horde Turn <a class="header-anchor" href="#horde-turn" aria-label="Permalink to &quot;Horde Turn&quot;">​</a></h2><p>On each Horde turn:</p><ol><li>Reveal the top card of the Horde library.</li><li>If it is a Zombie token, keep revealing cards.</li><li>Stop when a non-token card is revealed.</li><li>Cast all revealed tokens.</li><li>Cast the revealed non-token card last.</li><li>Move to combat.</li></ol><p>All Zombies have haste and must attack each turn if able.</p><h2 id="damaging-the-horde" tabindex="-1">Damaging The Horde <a class="header-anchor" href="#damaging-the-horde" aria-label="Permalink to &quot;Damaging The Horde&quot;">​</a></h2><p>The Horde has no life total. For each point of damage dealt to the Horde, mill one card from the top of the Horde library.</p><p>The Survivors win when:</p><ul><li>The Horde library is empty.</li><li>The Horde controls no Zombies.</li></ul><p>The Horde wins when:</p><ul><li>The Survivors&#39; shared life total reaches 0.</li></ul><h2 id="rules-notes" tabindex="-1">Rules Notes <a class="header-anchor" href="#rules-notes" aria-label="Permalink to &quot;Rules Notes&quot;">​</a></h2><ul><li>The Horde deck should avoid cards that require decisions.</li><li>If the Horde must make a choice, make the choice randomly.</li><li>Horde tokens and spells use the stack and can be responded to.</li><li>The Horde has infinite mana, so effects like Propaganda and Mana Leak do not function as normal answers.</li><li>If a permanent is returned to the Horde&#39;s hand, it is cast again during the Horde&#39;s next main phase.</li><li>If something does not work cleanly, the table should choose the fairest execution or cycle the problematic card.</li></ul><h2 id="original-zombie-horde-deck" tabindex="-1">Original Zombie Horde Deck <a class="header-anchor" href="#original-zombie-horde-deck" aria-label="Permalink to &quot;Original Zombie Horde Deck&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1 Call to the Grave</span></span>
<span class="line"><span>2 Bad Moon</span></span>
<span class="line"><span>1 Plague Wind</span></span>
<span class="line"><span>1 Damnation</span></span>
<span class="line"><span>1 Yixlid Jailer</span></span>
<span class="line"><span>1 Forsaken Wastes</span></span>
<span class="line"><span>2 Nested Ghoul</span></span>
<span class="line"><span>2 Infectious Horror</span></span>
<span class="line"><span>2 Delirium Skeins</span></span>
<span class="line"><span>1 Blind Creeper</span></span>
<span class="line"><span>2 Soulless One</span></span>
<span class="line"><span>2 Vengeful Dead</span></span>
<span class="line"><span>1 Fleshbag Marauder</span></span>
<span class="line"><span>1 Carrion Wurm</span></span>
<span class="line"><span>3 Maggot Carrier</span></span>
<span class="line"><span>4 Cackling Fiend</span></span>
<span class="line"><span>1 Death Baron</span></span>
<span class="line"><span>1 Grave Titan</span></span>
<span class="line"><span>2 Severed Legion</span></span>
<span class="line"><span>1 Skulking Knight</span></span>
<span class="line"><span>1 Undead Warchief</span></span>
<span class="line"><span>1 Twilight&#39;s Call</span></span>
<span class="line"><span>1 Army of the Damned</span></span>
<span class="line"><span>1 Endless Ranks of the Dead</span></span>
<span class="line"><span>2 Rotting Fensnake</span></span>
<span class="line"><span>1 Unbreathing Horde</span></span>
<span class="line"><span>1 Walking Corpse</span></span>
<span class="line"><span>5 Zombie Giant Tokens</span></span>
<span class="line"><span>55 Zombie Tokens</span></span></code></pre></div><p>The article notes that Infectious Host was changed to Infectious Horror from the original posted list.</p><h2 id="design-notes" tabindex="-1">Design Notes <a class="header-anchor" href="#design-notes" aria-label="Permalink to &quot;Design Notes&quot;">​</a></h2><p>The article discusses a few early design choices:</p><ul><li>The deck needs variance, but dice-based variance felt inelegant.</li><li>Non-token cards create tension because players do not know whether the next reveal is harmless or devastating.</li><li>Sweepers and reset effects pressure Survivors to attack the Horde instead of turtling forever.</li><li>Scaling is difficult because every additional Survivor adds more draw steps, mana development, and actions.</li><li>Persistent effects such as Bad Moon help the Horde scale as the game goes longer.</li></ul><h2 id="future-idea-survivor-decks" tabindex="-1">Future Idea: Survivor Decks <a class="header-anchor" href="#future-idea-survivor-decks" aria-label="Permalink to &quot;Future Idea: Survivor Decks&quot;">​</a></h2><p>The editor&#39;s note suggests preconstructed Survivor decks designed and balanced against the Horde. This would make the format more plug-and-play for players without Commander decks and could create class-like roles for the Survivor team.</p><h2 id="acknowledgements-listed-by-source" tabindex="-1">Acknowledgements Listed By Source <a class="header-anchor" href="#acknowledgements-listed-by-source" aria-label="Permalink to &quot;Acknowledgements Listed By Source&quot;">​</a></h2><ul><li>Abram Jopp</li><li>Benjamin Weitz</li><li>Tyler Tyssedal</li><li>Andrea Shubert</li><li>Forrest Ryan</li></ul>`,36)])])}const m=a(t,[["render",r]]);export{u as __pageData,m as default};
